4	describe("Game of Life - nextGeneration", () => {
5	  it("returns an empty array when given no living cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent cells each with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("keeps a live cell alive with exactly 2 live neighbors (survival)", () => {
15	    // Three cells in a row: (0,0), (1,0), (2,0)
