17	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
18	    expect(result).toContainEqual([1, 0]);
19	  });
20	  it("keeps a live cell alive with exactly 3 live neighbors (survival)", () => {
21	    // 2x2 block: cell (0,0) has 3 live neighbors: (1,0), (0,1), (1,1)
22	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
23	    expect(result).toContainEqual([0, 0]);
