export const nextGeneration = (cells: Cell[]): Cell[] => {
  const isLive = (x: number, y: number): boolean =>
    cells.some(([cx, cy]) => cx === x && cy === y);

  const countLiveNeighbors = (x: number, y: number): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isLive(x + dx, y + dy)).length;

  const survives = (cell: Cell): boolean => {
    const liveNeighbors = countLiveNeighbors(cell[0], cell[1]);
    return liveNeighbors === 2 || liveNeighbors === 3;
  };

  const survivors = cells.filter(survives);

  const deadCandidates: Cell[] = [];
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      if (isLive(nx, ny)) continue;
      if (deadCandidates.some(([cx, cy]) => cx === nx && cy === ny)) continue;
      deadCandidates.push([nx, ny]);
    }
  }
  const births = deadCandidates.filter(([x, y]) => countLiveNeighbors(x, y) === 3);

  return [...survivors, ...births];
};

